   152→        LIMIT 1
   153→      ) yoo ON true
   154→      LEFT JOIN LATERAL (
   155→        SELECT
   156→          yr2.attendance,
   157→          yr2.staff_name,
   158→          yr2.deleted,
   159→          yr2.date_visit::text AS date_visit,
