/* ─── Portal dropdown select ─── */
function AppSelect({
  value, onChange, options, placeholder,
}: {
  value: string;
  onChange: (v: string) => void;
  options: string[];
  placeholder?: string;
}) {
  const [open, setOpen]   = useState(false);
  const btnRef  = useRef<HTMLButtonElement>(null);
  const dropRef = useRef<HTMLDivElement>(null);
  const [pos, setPos]     = useState({ top: 0, left: 0, width: 0 });

  const updatePos = () => {
    if (btnRef.current) {
      const r = btnRef.current.getBoundingClientRect();
      setPos({ top: r.bottom + 6, left: r.left, width: r.width });
    }
  };

  const handleOpen = () => {
    if (!open) updatePos();
    setOpen(o => !o);
  };

  useEffect(() => {
    if (!open) return;
    function onDown(e: MouseEvent) {
      const t = e.target as Node;
      if (
        btnRef.current && !btnRef.current.contains(t) &&
        dropRef.current && !dropRef.current.contains(t)
      ) setOpen(false);
    }
    function onScroll() { updatePos(); }
    document.addEventListener('mousedown', onDown);
    window.addEventListener('scroll', onScroll, true);
    return () => {
      document.removeEventListener('mousedown', onDown);
      window.removeEventListener('scroll', onScroll, true);
    };
  }, [open]);

  const isActive = !!value;

  return (
    <div className="relative">
      <button
        ref={btnRef}
        type="button"
        onClick={handleOpen}
        className={`w-full text-xs pl-4 pr-8 py-2.5 border rounded-xl focus:outline-none cursor-pointer shadow-3xs transition-all duration-150 flex items-center gap-2 text-left ${
          isActive
            ? 'bg-white/80 border-neutral-300 text-neutral-900'
            : 'bg-white/80 hover:bg-white border-neutral-200/70 text-neutral-400'
        }`}
      >
        <span className={`font-semibold truncate flex-1 ${isActive ? 'text-neutral-900' : 'text-neutral-400'}`}>
          {value || placeholder || '— Выбрать —'}
        </span>
      </button>
      <ChevronDown className={`absolute right-2.5 top-2.5 w-3.5 h-3.5 pointer-events-none transition-transform duration-150 ${open ? 'rotate-180' : ''} ${isActive ? 'text-neutral-500' : 'text-neutral-400'}`} />

      {open && createPortal(
        <div
          ref={dropRef}
          style={{ position: 'fixed', top: pos.top, left: pos.left, width: pos.width, zIndex: 9999 }}
          className="bg-white border border-neutral-100 rounded-2xl shadow-2xl py-1.5 overflow-hidden"
        >
          {placeholder && (
            <button
              type="button"
              onClick={() => { onChange(''); setOpen(false); }}
              className="w-full text-left px-4 py-2.5 text-xs text-neutral-400 hover:bg-neutral-50 transition-colors duration-100 cursor-pointer font-medium"
            >
              {placeholder}
            </button>
          )}
          {options.map(opt => (
            <button
              key={opt}
              type="button"
              onClick={() => { onChange(opt); setOpen(false); }}
              className={`w-full text-left px-4 py-2.5 text-xs transition-colors duration-100 cursor-pointer flex items-center justify-between gap-3 ${
                value === opt
                  ? 'bg-indigo-50 text-indigo-700 font-bold'
                  : 'text-neutral-700 font-medium hover:bg-neutral-50'
              }`}
            >
              <span>{opt}</span>
              {value === opt && <Check className="w-3.5 h-3.5 text-indigo-500 shrink-0" />}
            </button>
          ))}
        </div>
      , document.body)}
    </div>
  );
}

