    92→    if (d) { setViewYear(d.getFullYear()); setViewMonth(d.getMonth()); }
    93→  }, [value]);
    94→
    95→  function prevMonth() {
    96→    if (viewMonth === 0) { setViewMonth(11); setViewYear(y => y - 1); }
    97→    else setViewMonth(m => m - 1);
    98→  }
    99→  function nextMonth() {
